function writingDocAudit(shortDocs,civicDocs,essayDocs,mcqDocKeys,profile){const sectionDuplicates=(section,docs)=>{const seen=new Set();const duplicates=[];docs.forEach(doc=>{if(docBlocked(doc,seen))duplicates.push({key:doc.docGroupKey,section});addDocKeys(doc,seen)});return duplicates};const shortKeys=docKeySet(shortDocs);const longDocs=civicDocs.length?civicDocs:essayDocs;const overlaps=longDocs.filter(doc=>docBlocked(doc,shortKeys)).map(doc=>({key:doc.docGroupKey,section:"crq-saq-overlap"}));const allDocs=[...shortDocs,...longDocs];const mcqOverlaps=allDocs.filter(doc=>docBlocked(doc,mcqDocKeys||new Set())).map(doc=>({key:doc.docGroupKey,section:"mcq-writing-overlap"}));const missingImages=allDocs.filter(doc=>!hasStimulusImages(doc)).map(doc=>({key:doc.docGroupKey,section:"missing-image"}));const mismatches=courseStimulusMismatches(allDocs);const mergedSources=allDocs.filter(doc=>(doc.questionIds||[]).length>1&&String(doc.source||"").includes(" / ")).map(doc=>({key:doc.docGroupKey,section:"merged-source",source:doc.source}));const unknownSources=allDocs.filter(doc=>!trustedDocSource(doc)).map(doc=>({key:doc.docGroupKey,section:"unknown-source",source:doc.source}));const duplicates=[...sectionDuplicates("crq-saq",shortDocs),...sectionDuplicates("civic-literacy",civicDocs),...sectionDuplicates(profile.id==="global-history-ii"?"enduring-issues":"civic-literacy-essay",essayDocs),...overlaps];const requiredDocCountsOk=profile.id==="us-history"?shortDocs.length===4&&civicDocs.length===6&&essayDocs.length===6:shortDocs.length===4&&civicDocs.length===0&&essayDocs.length===5;const writingIntegrityOk=requiredDocCountsOk&&!duplicates.length&&!mcqOverlaps.length&&!missingImages.length&&!mismatches.length&&!mergedSources.length&&!unknownSources.length;return {shortDocs:shortDocs.length,civicDocs:civicDocs.length,essayDocs:essayDocs.length,essayDocMinimum:profile.essayDocMinimum,duplicateWritingDocs:duplicates.length,duplicates,mcqWritingOverlap:mcqOverlaps.length,mcqOverlaps,missingWritingImages:missingImages.length,missingImages,courseStimulusMismatches:mismatches.length,mismatches,mergedWritingSources:mergedSources.length,mergedSources,unknownWritingSources:unknownSources.length,unknownSources,requiredDocCountsOk,writingIntegrityOk}}
function buildExamCandidate(course,timeLimit,attempt=1){const profile=PROFILES[course];const all=courseQuestions(course);const sourced=all.filter(sourceBased);const imageSourced=sourced.filter(hasStimulusImages);const direct=all.filter(q=>!sourceBased(q));const imageMcqPool=uniqueQuestionsByDocGroup(imageSourced);const directMcqPool=uniqueQuestionsByDocGroup(direct);let mcqPool=imageMcqPool.length>=28?imageMcqPool:imageMcqPool.concat(directMcqPool);const mcq=balancedPick(mcqPool,28).map((question,index)=>displayQuestion(question,index));const mcqDocKeys=docKeySet(mcq);const needed=profile.id==="us-history"?10:9;const imageDocGroups=docGroupsFromQuestions(imageSourced).filter(doc=>hasStimulusImages(doc)&&trustedDocSource(doc));let docGroups=imageDocGroups.filter(doc=>!docBlocked(doc,mcqDocKeys));const mcqOverlapFallback=docGroups.length<needed;if(mcqOverlapFallback)docGroups=imageDocGroups;const usedWriting=new Set();let shortDocs=addUsedDocs(pickDocPairs(docGroups,profile.shortTasks.length,usedWriting,profile),usedWriting);let civicDocs=[];let essayDocs=[];if(profile.id==="us-history"){civicDocs=addUsedDocs(pickClusterDocs(docGroups,6,usedWriting,profile),usedWriting);if(civicDocs.length<6)civicDocs=addUsedDocs([...civicDocs,...fillDocs(docGroups,6-civicDocs.length,usedWriting)],usedWriting);essayDocs=civicDocs.slice()}else{essayDocs=addUsedDocs(pickClusterDocs(docGroups,5,usedWriting,profile),usedWriting);if(essayDocs.length<5)essayDocs=addUsedDocs([...essayDocs,...fillDocs(docGroups,5-essayDocs.length,usedWriting)],usedWriting)}if(shortDocs.length<profile.shortTasks.length*2)shortDocs=addUsedDocs([...shortDocs,...fillDocs(docGroups,profile.shortTasks.length*2-shortDocs.length,usedWriting)],usedWriting);const shortTasks=profile.shortTasks.map((task,i)=>({...task,id:"short-"+(i+1),docs:shortDocs.slice(i*2,i*2+2).map((doc,j)=>makeDoc(doc,i*2+j))}));const scaffoldTasks=(profile.scaffoldPrompts||[]).map((prompt,i)=>({id:"scaffold-"+(i+1),title:"Civic SAQ "+(i+1),prompt,points:1,docs:civicDocs[i]?[makeDoc(civicDocs[i],i)]:[]}));essayDocs=essayDocs.map(makeDoc);const audit={imageBacked:imageSourced.length,sourceWithoutImages:sourced.length-imageSourced.length,writingGroups:docGroups.length,mcqDocGroups:new Set(mcq.map(docGroupKey)).size,mcqOverlapFallback,assemblyAttempt:attempt,...writingDocAudit(shortDocs,civicDocs,essayDocs,mcqDocKeys,profile)};return {id:profile.id+"-"+Date.now(),course,profileId:profile.id,timeLimit:Number(timeLimit),builtAt:new Date().toISOString(),audit,mcq,shortTasks,scaffoldTasks,essay:{id:"essay",title:profile.essayTitle,points:profile.essayMax,prompt:profile.essayPrompt,docs:essayDocs}}}
function examQualityScore(exam){const audit=exam.audit||{};let score=0;if(exam.mcq.length===28)score+=20;if(audit.mcqDocGroups===28)score+=20;if(audit.writingIntegrityOk)score+=60;if(!audit.mcqOverlapFallback)score+=10;score-=Number(audit.duplicateWritingDocs||0)*20;score-=Number(audit.missingWritingImages||0)*30;score-=Number(audit.courseStimulusMismatches||0)*30;score-=Number(audit.mcqWritingOverlap||0)*12;return score}
function assembleExam(course,timeLimit,form=null){const exact=form||selectedReleasedForm(course)||releasedForm(course);if(exact)return buildExactReleasedExam(course,timeLimit,exact);let best=null;for(let attempt=1;attempt<=12;attempt++){const candidate=buildExamCandidate(course,timeLimit,attempt);candidate.audit.assemblyAttempts=attempt;if(!best||examQualityScore(candidate)>examQualityScore(best))best=candidate;if(candidate.audit.writingIntegrityOk&&candidate.audit.mcqDocGroups===28&&!candidate.audit.mcqOverlapFallback)return candidate}if(best)best.audit.assemblyAttempts=12;return best}
function examSourceLock(exam){const audit=exam?.audit||{};const profile=PROFILES[exam?.course]||{};const issues=[];const mcq=exam?.mcq||[];if(!exam)issues.push("exam did not build");if(exam&&exam.mode!=="exact-released-form")issues.push("not an exact released form");if(mcq.length!==28)issues.push("28 MCQs not present");if(mcq.some(q=>!hasStimulusImages(q)))issues.push("one or more official MCQ page images are missing");const orderOk=mcq.every((q,index)=>Number(q.officialQuestionNumber||q.number||0)===index+1);if(mcq.length&& !orderOk)issues.push("MCQs are not in official order");if(audit.requiredDocCountsOk!==true)issues.push("document count does not match the selected exam shape");if(audit.writingIntegrityOk!==true)issues.push(auditStatusText(audit));if(!exam?.conversionTable?.rows)issues.push("official conversion chart missing");if(!exam?.officialLinks?.exam||!exam?.officialLinks?.scoringKey||!exam?.officialLinks?.conversionChart)issues.push("official scoring links missing");const docSummary=profile.id==="us-history"?`${audit.shortDocs||0} short-essay docs, ${audit.civicDocs||0} Civic SAQ docs, ${audit.essayDocs||0} Civic essay docs`:`${audit.shortDocs||0} CRQ docs, ${audit.essayDocs||0} Enduring Issues docs`;return{ok:!issues.length,issues,summary:`${mcq.length} MCQs · ${docSummary} · ${auditStatusText(audit)}`}}
function sourceLockPreview(course,forms){const candidates=(forms||[]).filter(Boolean);const locks=candidates.map(form=>{const exam=buildExactReleasedExam(course,Number($("#timerSelect")?.value||0),form);return{form,exam,lock:examSourceLock(exam)}});return{locks,ok:locks.length>0&&locks.every(item=>item.lock.ok),bad:locks.filter(item=>!item.lock.ok)}}
function sourceLockPreviewHtml(course,forms,selected,profile){const candidates=selected==="random"?forms:forms.filter(form=>form.id===selected||form.administration===selected);const label=selected==="random"?`All ${forms.length} random candidates`:(candidates[0]?.administration||"Selected exam");const preview=sourceLockPreview(course,candidates);const docLine=profile.id==="us-history"?"4 Part II docs + 6 Civic SAQ docs + 6 Civic essay docs":"4 CRQ docs + 5 Enduring Issues docs";const ok=preview.ok;const details=ok?`${label}: 28 image-backed MCQs, ${docLine}, official key, rubric shape, and conversion chart verified.`:`Repair needed before launch: ${preview.bad.slice(0,2).map(item=>(item.form?.administration||"form")+": "+item.lock.issues.join(", ")).join(" · ")||"no digitized form found"}`;return{ok,html:'<div class="source-lock-preview '+(ok?'good':'bad')+'"><strong>Source Lock: '+(ok?'verified':'blocked')+'</strong><span>'+esc(details)+'</span></div>'}}
function renderSetup(){const courses=Object.keys(PROFILES).filter(c=>courseQuestions(c).length||interactiveForms(c).length);$("#courseSelect").innerHTML=courses.map(c=>'<option value="'+esc(c)+'">'+esc(PROFILES[c].label)+'</option>').join("");const params=new URLSearchParams(location.search);const requestedCourse=params.get("course");if(requestedCourse&&courses.includes(requestedCourse))$("#courseSelect").value=requestedCourse;state.profile=PROFILES[$("#courseSelect").value||courses[0]];populateFormSelect();const requestedForm=params.get("form");if(requestedForm&&$("#formSelect").querySelector('option[value="'+CSS.escape(requestedForm)+'"]'))$("#formSelect").value=requestedForm;const forms=courses.reduce((sum,course)=>sum+interactiveForms(course).length,0);const releasedMcqs=courses.reduce((sum,course)=>sum+interactiveForms(course).reduce((inner,form)=>inner+(form.mcq||[]).length,0),0);const stim=courses.reduce((sum,course)=>sum+interactiveForms(course).reduce((inner,form)=>inner+(form.mcq||[]).filter(hasStimulusImages).length,0),0);$("#setupMetrics").innerHTML=[[forms,"graded official exams"],[releasedMcqs,"keyed MCQs"],[stim,"official page images"]].map(m=>'<div class="metric"><strong>'+esc(m[0])+'</strong><span>'+esc(m[1])+'</span></div>').join("");renderPreview();$("#resumeBtn").classList.toggle("hidden",!loadSaved(false))}
function renderPreview(){const course=$("#courseSelect").value;const profile=PROFILES[course];const forms=interactiveForms(course);const selected=$("#formSelect")?.value||"random";const picked=selected==="random"?null:forms.find(form=>form.id===selected||form.administration===selected);const randomLine=selected==="random"?"Random from "+forms.length+" official past exams.":"Selected: "+(picked?.administration||"official graded exam")+".";const writingLine=profile.id==="us-history"?"10 pt Part II short essays · 6 pt Civic Literacy SAQ · 5 pt civic essay":"7 pt Part II CRQ · 5 pt enduring issues essay";const trust=['Official past exam','Approximate score report','Writing feedback','Source-based practice'];const lock=sourceLockPreviewHtml(course,forms,selected,profile);const start=$("#startBtn");if(start)start.disabled=!lock.ok;$("#examPreview").innerHTML='<strong>'+esc(profile.title)+'</strong><br>'+esc(randomLine)+'<br>Use one full past exam to practice pacing, source reading, and writing from start to finish.<br><br><strong>Shape</strong><br>28 MCQ · '+esc(writingLine)+'<br><br><strong>Scoring</strong><br>Get an approximate score report based on the official multiple-choice key, the matching writing guide, and the form conversion chart when available.'+lock.html+'<div class="trust-list">'+trust.map(item=>'<span>'+esc(item)+'</span>').join("")+'</div>'}
function startExam(){clearSaved();const course=$("#courseSelect").value;state.profile=PROFILES[course];state.timeLimit=Number($("#timerSelect").value);const picked=selectedReleasedForm(course);state.exam=assembleExam(course,state.timeLimit,picked);const lock=examSourceLock(state.exam);if(!lock.ok){state.exam=null;const start=$("#startBtn");if(start)start.disabled=true;$("#examPreview").insertAdjacentHTML("afterbegin",'<div class="source-lock-preview bad"><strong>Source Lock: blocked</strong><span>'+esc(lock.issues.join(", "))+'</span></div>');return}state.section="mcq";state.mcqIndex=0;state.answers={};state.marked={};state.writing={};state.submitted=false;state.result=null;state.sectionMs={mcq:0,short:0,scaffold:0,essay:0,review:0,official:0};state.startMs=Date.now();state.deadlineMs=state.timeLimit>0?state.startMs+state.timeLimit*60000:0;state.sectionStartedMs=Date.now();show("examScreen");renderExam();startTimer();saveProgress()}
function resumeExam(){const saved=loadSaved(true);if(!saved)return;show("examScreen");renderExam();startTimer()}
function loadSaved(apply){try{const raw=localStorage.getItem(SAVE_KEY);if(!raw)return null;const saved=JSON.parse(raw);if(!savedExamCurrent(saved)){clearSaved();return null}if(apply){Object.assign(state,saved);state.profile=PROFILES[state.exam.course];state.sectionStartedMs=Date.now();}return saved}catch{clearSaved();return null}}
function saveProgress(){if(!state.exam||state.submitted)return;try{localStorage.setItem(SAVE_KEY,JSON.stringify({exam:state.exam,profile:state.profile,section:state.section,mcqIndex:state.mcqIndex,answers:state.answers,marked:state.marked,writing:state.writing,startMs:state.startMs,deadlineMs:state.deadlineMs,timeLimit:state.timeLimit,sectionMs:currentSectionMs(),submitted:false}))}catch{}}
function clearSaved(){try{localStorage.removeItem(SAVE_KEY)}catch{}}
function currentSectionMs(){const copy={...state.sectionMs};if(state.sectionStartedMs&&copy[state.section]!=null)copy[state.section]+=Date.now()-state.sectionStartedMs;return copy}
function switchSection(section){if(state.submitted)return;state.sectionMs=currentSectionMs();state.sectionStartedMs=Date.now();state.section=section;renderExam();saveProgress()}
function startTimer(){if(state.timer)clearInterval(state.timer);state.timer=setInterval(()=>{renderTimers();if(state.deadlineMs&&Date.now()>=state.deadlineMs&&!state.submitted)submitExam(true)},1000);renderTimers()}
function renderTimers(){if(!state.exam){$("#timerStrip").innerHTML="";return}const remaining=state.deadlineMs?Math.max(0,Math.floor((state.deadlineMs-Date.now())/1000)):0;const elapsed=Math.floor((Date.now()-state.startMs)/1000);$("#timerStrip").innerHTML='<span class="pill">'+(state.deadlineMs?'Time left '+fmt(remaining):'Untimed')+'</span><span class="pill">Elapsed '+fmt(elapsed)+'</span>';$("#overallClock").textContent=state.deadlineMs?fmt(remaining):fmt(elapsed);const sectionElapsed=Math.floor((currentSectionMs()[state.section]||0)/1000);const target=state.profile.sectionTargets[state.section]||0;$("#sectionClock").textContent=fmt(sectionElapsed)+(target?' / '+target+'m':'')}
function auditStatusText(audit){if(!audit)return "Source set audit";if(audit.writingIntegrityOk)return audit.civicDocs?"Short docs separate; six Civic Literacy docs verified.":"CRQ docs separate; five essay docs verified.";const flags=[];if(!audit.requiredDocCountsOk)flags.push("wrong document count");if(audit.duplicateWritingDocs)flags.push("repeat docs");if(audit.mcqWritingOverlap)flags.push("MCQ overlap");if(audit.missingWritingImages)flags.push("missing images");if(audit.courseStimulusMismatches)flags.push("course mismatch");if(audit.mergedWritingSources)flags.push("merged sources");if(audit.unknownWritingSources)flags.push("unknown sources");return flags.length?flags.join(", "):"audit warning"}
function sectionStatus(){const answered=Object.keys(state.answers).length;const shortDone=state.exam.shortTasks.filter(t=>wordCount(state.writing[t.id])>0).length;const scaffoldDone=(state.exam.scaffoldTasks||[]).filter(t=>wordCount(state.writing[t.id])>0).length;const essayDone=wordCount(state.writing.essay)>0?1:0;const writingTotal=state.exam.shortTasks.length+(state.exam.scaffoldTasks||[]).length+1;$("#answeredCount").textContent=answered+" / "+state.exam.mcq.length;$("#writingCount").textContent=(shortDone+scaffoldDone+essayDone)+" / "+writingTotal;const tile=$("#docAuditTile");if(tile){const ok=!!state.exam.audit?.writingIntegrityOk;tile.classList.toggle("good",ok);tile.classList.toggle("warn",!ok);tile.querySelector("strong").textContent=ok?"Verified":"Check";const text=$("#docAuditText");if(text)text.textContent=auditStatusText(state.exam.audit)}}
function renderTabs(){const tabs=[["mcq","Part I","MCQ"],["short","Part II",state.profile.id==="us-history"?"Short Essays":"CRQ"]];if((state.exam.scaffoldTasks||[]).length)tabs.push(["scaffold","Part IIIA","Civic SAQ"]);tabs.push(["essay",state.profile.id==="us-history"?"Part IIIB":"Part III","Essay"],["review","Review","Submit"]);$("#sectionTabs").style.gridTemplateColumns="repeat("+tabs.length+", minmax(0, 1fr))";$("#sectionTabs").innerHTML=tabs.map(t=>'<button class="tab '+(state.section===t[0]?'active':'')+'" data-section="'+t[0]+'"><small>'+t[1]+'</small>'+t[2]+'</button>').join("");$$(".tab").forEach(btn=>btn.addEventListener("click",()=>switchSection(btn.dataset.section)))}
function renderQuestionMap(){if(state.section!=="mcq"){$("#questionMap").innerHTML="";return}$("#questionMap").innerHTML=state.exam.mcq.map((q,i)=>'<button class="qdot '+(state.answers[q.id]?'answered ':'')+(state.marked[q.id]?'marked ':'')+(i===state.mcqIndex?'active':'')+'" data-index="'+i+'">'+(i+1)+'</button>').join("");$$(".qdot").forEach(btn=>btn.addEventListener("click",()=>{state.mcqIndex=Number(btn.dataset.index);renderExam();saveProgress()}))}
function renderExam(){if(state.exam?.mode!=="exact-released-form"){clearSaved();state.exam=null;show("setupScreen");renderSetup();return}$("#submitBtn").classList.remove("hidden");renderTabs();sectionStatus();renderQuestionMap();renderTimers();if(state.section==="mcq")renderMcq();if(state.section==="short")renderShort();if(state.section==="scaffold")renderScaffold();if(state.section==="essay")renderEssay();if(state.section==="review")renderReview()}
function inspectButton(img,label,source){return '<button class="inspect-btn" type="button" data-inspect-src="'+esc(img.src)+'" data-inspect-label="'+esc(label||img.label||"Source stimulus")+'" data-inspect-source="'+esc(source||"Released Regents source")+'">Expand Source</button>'}
function renderDocImages(docs){return docs.map((doc,i)=>{const images=cleanStimulusImages(doc);return '<article class="doc-card"><h3>Document '+(doc.docNumber||i+1)+'</h3><div class="source-line">'+esc(doc.source||doc.set||"Released Regents source")+'</div>'+(images.length?images.map(img=>'<figure class="stimulus-figure"><img data-source-img="1" src="'+esc(img.src)+'" alt="'+esc(img.label||"Document stimulus")+'"><figcaption>'+esc(img.label||"Stimulus")+'</figcaption>'+inspectButton(img,"Document "+(doc.docNumber||i+1)+" · "+(img.label||"Stimulus"),doc.source||doc.set)+'</figure>').join(""):'<p class="source-line">No separate image crop is available for this source.</p>')+'</article>'}).join("")}
function renderMcq(){const q=state.exam.mcq[state.mcqIndex];const images=cleanStimulusImages(q);const hasStim=images.length;$("#sectionKicker").textContent="Part I";$("#sectionTitle").textContent="Multiple Choice "+(state.mcqIndex+1)+" / "+state.exam.mcq.length;$("#workActions").innerHTML=(hasStim?inspectButton(images[0],"Question "+(state.mcqIndex+1)+" source",q.source||q.set):"")+'<button class="btn ghost" id="markBtn" type="button">'+(state.marked[q.id]?'Unmark':'Mark For Review')+'</button><button class="btn" id="prevBtn" type="button">Previous</button><button class="btn" id="nextBtn" type="button">Next</button>';const stimulus=hasStim?images.map(img=>'<figure class="stimulus-figure"><img data-source-img="1" src="'+esc(img.src)+'" alt="'+esc(img.label||"Stimulus image")+'"><figcaption>'+esc(img.label||"Original Regents stimulus")+'</figcaption>'+inspectButton(img,"Question "+(state.mcqIndex+1)+" · "+(img.label||"Stimulus"),q.source||q.set)+'</figure>').join(""):'<div class="stimulus-panel empty">No separate stimulus image for this item.</div>';$("#workArea").innerHTML='<div class="mcq-shell"><aside class="stimulus-panel '+(hasStim?'':'hidden')+'">'+stimulus+'</aside><section class="question-card"><div class="source-line">'+esc(q.course+" · "+q.set+" · "+q.source)+'</div><h3>'+esc(q.stem)+'</h3><div class="choices">'+q.displayedChoices.map(c=>'<button class="choice '+(state.answers[q.id]===c.label?'selected':'')+'" data-choice="'+esc(c.label)+'"><strong>'+esc(c.label)+'.</strong>'+esc(c.text)+'</button>').join("")+'</div></section></div>';$$(".choice").forEach(btn=>btn.addEventListener("click",()=>{state.answers[q.id]=btn.dataset.choice;renderExam();saveProgress()}));$("#markBtn").addEventListener("click",()=>{state.marked[q.id]=!state.marked[q.id];renderExam();saveProgress()});$("#prevBtn").disabled=state.mcqIndex===0;$("#nextBtn").disabled=state.mcqIndex>=state.exam.mcq.length-1;$("#prevBtn").addEventListener("click",()=>{state.mcqIndex=Math.max(0,state.mcqIndex-1);renderExam();saveProgress()});$("#nextBtn").addEventListener("click",()=>{state.mcqIndex=Math.min(state.exam.mcq.length-1,state.mcqIndex+1);renderExam();saveProgress()})}
function renderShort(){$("#sectionKicker").textContent="Part II";$("#sectionTitle").textContent=state.profile.shortTitle;const next=(state.exam.scaffoldTasks||[]).length?"scaffold":"essay";$("#workActions").innerHTML='<button class="btn" type="button" id="toNextWritingBtn">Go To '+(next==="scaffold"?"Civic SAQ":"Essay")+'</button>';$("#workArea").innerHTML='<div class="writing-stack">'+state.exam.shortTasks.map(task=>'<article class="writing-card"><h3>'+esc(task.title)+' <span class="source-line">'+task.points+' pts approx.</span></h3><div class="doc-grid">'+renderDocImages(task.docs)+'</div><ol class="prompt-list">'+task.prompts.map(p=>'<li>'+esc(p)+'</li>').join("")+'</ol><textarea data-writing="'+esc(task.id)+'" placeholder="Write your response here.">'+esc(state.writing[task.id]||"")+'</textarea><div class="word-row"><span id="words-'+esc(task.id)+'">'+wordCount(state.writing[task.id])+' words</span><span>Approximate rubric score appears after submission.</span></div></article>').join("")+'</div>';wireWritingTextareas();$("#toNextWritingBtn").addEventListener("click",()=>switchSection(next))}
function renderScaffold(){$("#sectionKicker").textContent="Part IIIA";$("#sectionTitle").textContent=state.profile.scaffoldTitle;$("#workActions").innerHTML='<button class="btn" type="button" id="toEssayBtn">Go To Essay</button>';$("#workArea").innerHTML='<div class="writing-stack">'+(state.exam.scaffoldTasks||[]).map(task=>'<article class="writing-card scaffold-card"><h3>'+esc(task.title)+' <span class="source-line">'+task.points+' pt approx.</span></h3><div class="doc-grid one">'+renderDocImages(task.docs)+'</div><p class="prompt-list">'+esc(task.prompt)+'</p><textarea data-writing="'+esc(task.id)+'" placeholder="Answer this Civic Literacy short-answer question with specific evidence.">'+esc(state.writing[task.id]||"")+'</textarea><div class="word-row"><span id="words-'+esc(task.id)+'">'+wordCount(state.writing[task.id])+' words</span><span>One specific, supported answer earns the practice point.</span></div></article>').join("")+'</div>';wireWritingTextareas();$("#toEssayBtn").addEventListener("click",()=>switchSection("essay"))}
function renderEssay(){$("#sectionKicker").textContent=state.profile.id==="us-history"?"Part IIIB":"Part III";$("#sectionTitle").textContent=state.profile.essayTitle;$("#workActions").innerHTML='<button class="btn" type="button" id="toReviewBtn">Review Exam</button>';const issueOptions=state.profile.issueTerms.slice(0,8).map(x=>'<span class="pill">'+esc(x)+'</span>').join("");const docNote=state.profile.id==="us-history"?"This is the same six-document Civic Literacy set used for Part IIIA by design. Use evidence from at least four documents for the essay.":"This Enduring Issues essay has five unique documents. Use evidence from at least three of the five.";$("#workArea").innerHTML='<div class="writing-stack"><article class="writing-card"><h3>'+esc(state.exam.essay.title)+' <span class="source-line">'+state.exam.essay.points+' pts approx.</span></h3><p class="source-line">'+esc(state.exam.essay.prompt)+'</p><p class="doc-set-note">'+esc(docNote)+'</p><div class="timer-strip">'+issueOptions+'</div><div class="doc-grid">'+renderDocImages(state.exam.essay.docs)+'</div><textarea data-writing="essay" placeholder="Write your essay here.">'+esc(state.writing.essay||"")+'</textarea><div class="word-row"><span id="words-essay">'+wordCount(state.writing.essay)+' words</span><span>Use document evidence, outside information, and clear analysis.</span></div></article></div>';wireWritingTextareas();$("#toReviewBtn").addEventListener("click",()=>switchSection("review"))}
function wireWritingTextareas(){$$("textarea[data-writing]").forEach(area=>{area.addEventListener("input",()=>{state.writing[area.dataset.writing]=area.value;const target=$("#words-"+area.dataset.writing);if(target)target.textContent=wordCount(area.value)+" words";sectionStatus();saveProgress()})})}
function wordCount(v){return String(v||"").trim().split(/\s+/).filter(Boolean).length}
function renderReview(){const unanswered=state.exam.mcq.filter(q=>!state.answers[q.id]).length;const marked=Object.values(state.marked).filter(Boolean).length;const shortDone=state.exam.shortTasks.filter(t=>wordCount(state.writing[t.id])>0).length;const scaffoldDone=(state.exam.scaffoldTasks||[]).filter(t=>wordCount(state.writing[t.id])>0).length;const essayDone=wordCount(state.writing.essay)>0;const scaffoldLine=(state.exam.scaffoldTasks||[]).length?'<div class="feedback-card"><strong>Part IIIA Civic SAQ</strong>'+scaffoldDone+' of '+state.exam.scaffoldTasks.length+' responses started</div>':"";const audit=state.exam.audit||{};const auditLine='<div class="feedback-card"><strong>Document Set Check</strong>'+esc(auditStatusText(audit))+'<br><span class="source-line">Short docs '+esc(audit.shortDocs||0)+' · Civic docs '+esc(audit.civicDocs||0)+' · Essay docs '+esc(audit.essayDocs||0)+' · MCQ overlap '+esc(audit.mcqWritingOverlap||0)+'</span></div>';$("#sectionKicker").textContent="Final Check";$("#sectionTitle").textContent="Review And Submit";$("#workActions").innerHTML='<button class="btn primary" id="submitTopBtn" type="button">Submit For Score</button>';$("#workArea").innerHTML='<div class="writing-stack"><div class="feedback-card"><strong>Multiple Choice</strong>'+unanswered+' unanswered · '+marked+' marked for review</div><div class="feedback-card"><strong>Short Answer</strong>'+shortDone+' of '+state.exam.shortTasks.length+' responses started</div>'+scaffoldLine+'<div class="feedback-card"><strong>Long Answer</strong>'+(essayDone?'Essay started':'Essay not started')+'</div>'+auditLine+'<div class="feedback-card"><strong>Approximate scoring</strong>MCQs are answer-keyed. Writing is scored by a practice rubric that checks claim, evidence, analysis, outside information, organization, and NYSED guide position. This is a practice estimate, not an official score.</div></div>';$("#submitTopBtn").addEventListener("click",()=>submitExam(false))}
function collectViewerItems(){return $$("[data-inspect-src]").map(btn=>({src:btn.dataset.inspectSrc,label:btn.dataset.inspectLabel||"Source",source:btn.dataset.inspectSource||""})).filter(item=>item.src)}
function openStimulusViewer(src,label,source){viewer.items=collectViewerItems();let index=viewer.items.findIndex(item=>item.src===src&&item.label===label);if(index<0)index=viewer.items.findIndex(item=>item.src===src);if(index<0){viewer.items=[{src,label:label||"Source",source:source||""}];index=0}viewer.index=index;viewer.zoom=1;renderStimulusViewer();$("#stimulusViewer").classList.remove("hidden");document.body.classList.add("viewer-open");$("#viewerClose").focus()}
function closeStimulusViewer(){$("#stimulusViewer").classList.add("hidden");document.body.classList.remove("viewer-open")}
function renderStimulusViewer(){const item=viewer.items[viewer.index]||{};const image=$("#viewerImage");if(item.src){image.hidden=false;image.src=item.src;image.alt=item.label||"Expanded stimulus"}else{image.hidden=true;image.src=EMPTY_PIXEL;image.alt=""}$("#viewerTitle").textContent=item.label||"Source";$("#viewerMeta").textContent=viewer.items.length?(item.source||"Released Regents source")+" · "+(viewer.index+1)+" of "+viewer.items.length:"No source selected";$("#viewerZoom").value=String(viewer.zoom);image.style.width=(viewer.zoom*100)+"%";$("#viewerPrev").disabled=viewer.items.length<2;$("#viewerNext").disabled=viewer.items.length<2}
function stepStimulusViewer(delta){if(!viewer.items.length)return;viewer.index=(viewer.index+delta+viewer.items.length)%viewer.items.length;viewer.zoom=1;renderStimulusViewer()}
function setStimulusZoom(value){viewer.zoom=clamp(Number(value)||1,.75,3);renderStimulusViewer()}
function textHasAny(text,terms){const n=norm(text);return terms.some(t=>n.includes(norm(t)))}
function docHitFlags(text,docs){const n=norm(text);return docs.map((doc,i)=>{const labels=["document "+(i+1),"doc "+(i+1),"source "+(i+1),"document "+(doc.docNumber||i+1),"doc "+(doc.docNumber||i+1),"source "+(doc.docNumber||i+1)];const byLabel=labels.some(l=>n.includes(l));const byKeyword=(doc.keywords||[]).some(k=>n.includes(k));return byLabel||byKeyword})}
function docHitCount(text,docs){return docHitFlags(text,docs).filter(Boolean).length}
function termHitCount(text,terms){const n=norm(text);return terms.filter(t=>n.includes(norm(t))).length}
function paragraphCount(text){return String(text||"").split(/\n\s*\n/).filter(p=>p.trim()).length}
function writingFeatures(text,docs){const wc=wordCount(text);const flags=docHitFlags(text,docs);const docHits=flags.filter(Boolean).length;const outsideHits=termHitCount(text,state.profile.courseTerms);const relationship=textHasAny(text,["relationship","cause","effect","similar","similarity","different","difference","turning point","changed","led to","resulted in","connected","because"]);const analysis=textHasAny(text,["because","therefore","as a result","led to","resulted in","caused","effect","impact","significant","shows that","this means","explains why","important"]);const context=textHasAny(text,["during","before","after","historical context","geographic context","at the time","century","war","revolution","movement","government","empire","constitution","amendment"])||outsideHits>0;const sourcing=textHasAny(text,["point of view","purpose","audience","bias","author","speaker","intended audience","perspective","reliable","source"]);const issue=textHasAny(text,state.profile.issueTerms)||textHasAny(text,["issue","constitutional","civic","enduring","problem","challenge","conflict","rights","power","inequality"]);const effect=textHasAny(text,["affected","impact","significant","important","hurt","helped","improved","weakened","strengthened","changed","expanded","limited"]);const continuity=textHasAny(text,["continued","continues","endured","persisted","over time","still","today","across time","changed over time","remained"]);const efforts=textHasAny(text,["effort","address","government","law","act","amendment","movement","reform","protest","court","decision","legislation","organization","group"]);const success=textHasAny(text,["successful","success","failed","extent","effective","ineffective","increased","decreased","expanded","limited","weakened","strengthened"]);const organized=paragraphCount(text)>=2||wc>=320;return {wc,flags,docHits,outsideHits,outside:outsideHits>0,relationship,analysis,context,sourcing,issue,effect,continuity,efforts,success,organized}}
function guideLabel(score,max){if(score===0)return "Not yet on guide";if(score===max)return "Top of this guide";if(max===5)return "Level "+score+" position";return score+"/"+max+" points located"}
function firstMissing(checks,fallback){const miss=checks.find(c=>!c.pass);return miss?miss.next:fallback}
function nextGuideTarget(score,max){if(score>=max)return max+"/"+max;return (max===5?halfPoint(score+.5):Math.min(max,Math.floor(score)+1))+"/"+max}
function guidePositionNote(score,max,checks,baseNote){const met=checks.filter(c=>c.pass).length;const total=checks.length;const next=score>=max?"Keep this score by adding precise evidence and clear explanation.":"Next guide target "+nextGuideTarget(score,max)+": "+firstMissing(checks,"Add more precise document evidence and explanation.");return (baseNote||"Practice rubric position located.")+" You are showing "+met+"/"+total+" rubric signals. "+next}
function clamp(n,min,max){return Math.max(min,Math.min(max,n))}
function halfPoint(score){return clamp(Math.round((Number(score)||0)*2)/2,0,5)}
function performanceLevel(scale,profileId){if(scale==null)return "n/a";if(scale<=54)return "Level 1";if(scale<=64)return "Level 2";if(profileId==="us-history"){if(scale<=75)return "Level 3";if(scale<=84)return "Level 4";return "Level 5"}if(scale<=78)return "Level 3";if(scale<=84)return "Level 4";return "Level 5"}
function essayColumnIndex(score,columns=ESSAY_COLUMNS){const essay=halfPoint(score);const index=columns.findIndex(v=>Number(v)===essay);return {essay,index:index<0?0:index}}
function conversionEstimate(mcqCorrect,shortTotal,scaffoldTotal,essayScore){const table=state.exam?.conversionTable;const columns=(table?.essayColumns||ESSAY_COLUMNS).map(Number);const e=essayColumnIndex(essayScore.score||0,columns);const base=state.profile.id==="global-history-ii"?clamp(mcqCorrect+shortTotal,0,35):clamp(mcqCorrect+shortTotal+scaffoldTotal,0,44);const dynamic=table?.rows?.[String(base)]?.[e.index];const fallback=state.profile.id==="global-history-ii"?GLOBAL_CONVERSION[base]?.[e.index]:US_CONVERSION[base]?.[e.index];const scale=dynamic??fallback??null;const rowLabel=state.profile.id==="global-history-ii"?"Part I + Part II":"Part I + Part II + Part IIIA";const essayLabel=state.profile.id==="global-history-ii"?"Part III essay":"Part IIIB essay";const source=dynamic==null?"January 2026 fallback chart":(state.exam.administration+" official conversion chart");return {scale,level:performanceLevel(scale,state.profile.id),base,essay:e.essay,scaffold:scaffoldTotal,source,note:source+": "+rowLabel+" row "+base+", "+essayLabel+" column "+e.essay+"."}}
function scoreShort(task,text){const f=writingFeatures(text,task.docs);if(!f.wc){const empty=task.prompts.map((p,i)=>({label:"Prompt "+(i+1),pass:false,next:"Write a supported response for this prompt."}));return {score:0,max:task.points,comments:["No response entered."],checks:empty,position:guideLabel(0,task.points),sourceNote:state.profile.shortRubric}}let checks=[];if(state.profile.id==="global-history-ii"&&task.points===3){checks=[{label:"Historical circumstances/context for Document 1",pass:f.context&&f.flags[0],next:"Add the time, place, event, or larger situation around Document 1."},{label:"Sourcing skill for Document 2",pass:f.sourcing&&f.flags[1],next:"Explain point of view, purpose, audience, or bias using Document 2."},{label:"Relationship using both documents",pass:f.relationship&&f.analysis&&f.flags[0]&&f.flags[1],next:"Name the relationship and explain it with evidence from both documents."}]}else if(state.profile.id==="global-history-ii"&&task.points===4){checks=[{label:"Context for Document 3",pass:f.context&&f.flags[0],next:"Explain the historical or geographic context for Document 3."},{label:"Context for Document 4",pass:f.context&&f.flags[1],next:"Explain the historical or geographic context for Document 4."},{label:"Identify the relationship or turning point",pass:f.relationship&&(f.flags[0]||f.flags[1]),next:"Identify a clear turning point, similarity, difference, or cause/effect relationship."},{label:"Explain why it matters using both documents",pass:f.analysis&&f.flags[0]&&f.flags[1],next:"Use evidence from both documents to explain why the relationship matters."}]}else{checks=[{label:"Historical context",pass:f.context,next:"Open with the larger historical setting around the documents."},{label:"Relationship between the documents",pass:f.relationship,next:"Name and explain cause/effect, similarity/difference, or turning point."},{label:"Evidence from both documents",pass:f.flags[0]&&f.flags[1],next:"Use specific evidence from both documents."},{label:"Analysis and depth",pass:f.analysis&&f.wc>=120,next:"Explain why the evidence matters instead of summarizing it."},{label:"Outside information",pass:f.outside,next:"Add one accurate course detail beyond the documents."}]}const score=Math.min(task.points,checks.filter(c=>c.pass).length);const comments=[firstMissing(checks,"This response is at the top of the practice guide for this task.")];return {score,max:task.points,comments,checks,position:guideLabel(score,task.points),sourceNote:state.profile.shortRubric}}
function scoreEssay(text,docs){const f=writingFeatures(text,docs);const minDocs=state.profile.essayDocMinimum||3;if(!f.wc){const empty=[{label:"Claim or issue",pass:false,next:"State the enduring issue or civic issue."},{label:"Document evidence",pass:false,next:"Use specific evidence from the required number of documents."},{label:"Analysis",pass:false,next:"Explain why the evidence proves the issue."},{label:"Outside information",pass:false,next:"Add accurate outside information."},{label:"Organization",pass:false,next:"Use organized paragraphs."}];return {score:0,max:state.profile.essayMax,comments:["No essay entered."],docHits:0,checks:empty,position:guideLabel(0,state.profile.essayMax),sourceNote:state.profile.essayRubric}}let checks=[];if(state.profile.id==="global-history-ii"){checks=[{label:"Identifies and explains one enduring issue",pass:f.issue,next:"Name one enduring issue and define it in historical terms."},{label:"Uses at least three of the five documents",pass:f.docHits>=3,next:"Use evidence from at least three of the five essay documents."},{label:"Shows significance or effect on people",pass:f.effect,next:"Explain how the issue affected people or was affected by people."},{label:"Shows endurance, continuity, or change over time",pass:f.continuity,next:"Explain how the issue continued or changed across time."},{label:"Uses outside information",pass:f.outsideHits>=1,next:"Add a specific Global History example beyond the documents."},{label:"Analytical and organized argument",pass:f.analysis&&f.organized,next:"Use paragraphs and explain why each example proves the argument."}]}else{checks=[{label:"Identifies the civic or constitutional issue",pass:f.issue,next:"Name the constitutional or civic issue directly."},{label:"Explains historical circumstances",pass:f.context,next:"Describe the historical circumstances around the issue."},{label:"Explains efforts to address the issue",pass:f.efforts,next:"Explain efforts by people, groups, courts, or government."},{label:"Discusses extent of success",pass:f.success||f.effect,next:"Discuss how successful the efforts were and where limits remained."},{label:"Uses at least four documents",pass:f.docHits>=minDocs,next:"Use evidence from at least four documents for the Civic Literacy guide."},{label:"Outside information and organization",pass:f.outside&&f.analysis&&f.organized,next:"Add outside information and organize it into a clear argument."}]}let score=0;if(f.issue||f.docHits>=1||f.wc>=50)score=1;if(f.issue&&f.docHits>=1&&f.wc>=90)score=2;if(f.issue&&f.docHits>=Math.min(2,minDocs)&&f.analysis&&(f.outside||f.organized)&&f.wc>=150)score=3;if(f.issue&&f.docHits>=minDocs&&f.analysis&&f.outside&&f.organized&&(state.profile.id==="global-history-ii"?(f.effect||f.continuity):(f.context&&f.efforts))&&f.wc>=240)score=4;if(score===4&&f.outsideHits>=2&&f.wc>=360&&(state.profile.id==="global-history-ii"?(f.effect&&f.continuity):(f.context&&f.efforts&&(f.success||f.effect))))score=5;const passCount=checks.filter(c=>c.pass).length;if(score>0&&score<5&&passCount>=score+2&&f.wc>=110+score*45)score+=.5;score=halfPoint(Math.min(state.profile.essayMax,score));const comments=[firstMissing(checks,"This essay is positioned at the top of the practice guide.")];return {score,max:state.profile.essayMax,comments,docHits:f.docHits,checks,position:guideLabel(score,state.profile.essayMax),sourceNote:state.profile.essayRubric}}
function scoreScaffold(task,text){const f=writingFeatures(text,task.docs);const checks=[{label:"Specific answer",pass:f.wc>=18,next:"Write a complete, specific answer."},{label:"Uses this document",pass:f.docHits>=1,next:"Use evidence from the document."},{label:"Explains the civic issue",pass:f.issue||f.context||f.efforts||f.effect,next:"Connect the answer to the civic issue."}];const pass=checks.filter(c=>c.pass).length>=2;return {score:pass?1:0,max:1,comments:[firstMissing(checks,"This Civic SAQ answer earns the practice point.")],checks,position:pass?"1/1 point located":"Not yet on guide",sourceNote:state.profile.scaffoldRubric||""}}
function gradeExam(){const mcqCorrect=state.exam.mcq.filter(q=>state.answers[q.id]===q.correct).length;const missed=state.exam.mcq.filter(q=>state.answers[q.id]!==q.correct);const shortScores=state.exam.shortTasks.map(t=>scoreShort(t,state.writing[t.id]||""));const scaffoldScores=(state.exam.scaffoldTasks||[]).map(t=>scoreScaffold(t,state.writing[t.id]||""));const essayScore=scoreEssay(state.writing.essay||"",state.exam.essay.docs);const shortTotal=shortScores.reduce((s,r)=>s+r.score,0);const scaffoldTotal=scaffoldScores.reduce((s,r)=>s+r.score,0);const raw=mcqCorrect+shortTotal+scaffoldTotal+essayScore.score;const rawMax=28+state.profile.shortMax+(state.profile.scaffoldMax||0)+state.profile.essayMax;const conversion=conversionEstimate(mcqCorrect,shortTotal,scaffoldTotal,essayScore);const percent=conversion.scale??Math.round(raw/rawMax*100);return {mcqCorrect,missed,shortScores,scaffoldScores,essayScore,shortTotal,scaffoldTotal,raw,rawMax,percent,conversion}}
function topMissedSets(missed){const counts={};missed.forEach(q=>{counts[q.set]=(counts[q.set]||0)+1;(q.tags||[]).slice(0,3).forEach(t=>counts[t]=(counts[t]||0)+1)});return Object.entries(counts).sort((a,b)=>b[1]-a[1]).slice(0,5)}
function scoredWritingChecks(result){const rows=[];result.shortScores.forEach((score,i)=>{const task=state.exam.shortTasks[i]||{};(score.checks||[]).forEach(check=>rows.push({...check,task:task.title||"Short Answer",section:"short"}))});(result.scaffoldScores||[]).forEach((score,i)=>{const task=state.exam.scaffoldTasks[i]||{};(score.checks||[]).forEach(check=>rows.push({...check,task:task.title||"Civic SAQ",section:"scaffold"}))});(result.essayScore.checks||[]).forEach(check=>rows.push({...check,task:state.profile.essayTitle,section:"essay"}));return rows}
function failedWritingChecks(result,pattern){return scoredWritingChecks(result).filter(check=>!check.pass&&pattern.test([check.label,check.next,check.task,check.section].join(" ")))}
function skillRow(label,pass,detail,next,priority){return {label,status:pass?"Secure":priority?"Priority":"Target",detail,next,weak:!pass}}
function skillReport(result){const mcqPct=Math.round(result.mcqCorrect/28*100);const stimMiss=result.missed.filter(sourceBased).length;const directMiss=result.missed.length-stimMiss;const contextMiss=failedWritingChecks(result,/context|historical circumstances|geographic/i).length;const relationMiss=failedWritingChecks(result,/relationship|turning point|cause|effect|similar|difference/i).length;const docMiss=failedWritingChecks(result,/document evidence|documents|evidence from|uses at least|use specific evidence/i).length;const outsideMiss=failedWritingChecks(result,/outside information|outside detail|course detail/i).length;const argumentMiss=failedWritingChecks(result,/analysis|organized|organization|significance|extent|success|endurance|continuity/i).length;const minDocs=state.profile.essayDocMinimum||3;const docNeed=state.profile.id==="us-history"?"four":"three";const scaffoldRow=(result.scaffoldScores||[]).length?skillRow("Civic SAQ accuracy",result.scaffoldTotal>=5,result.scaffoldTotal+"/"+(state.profile.scaffoldMax||0)+" Part IIIA points located.","Answer each Civic SAQ with one specific fact from that document, then connect it to the civic issue.",result.scaffoldTotal<4):null;const pace=state.sectionMs||{};const slow=Object.entries(state.profile.sectionTargets||{}).filter(([section,minutes])=>minutes&&pace[section]>minutes*60000*1.2).map(([section])=>section.toUpperCase());const rows=[skillRow("MCQ source reading",stimMiss<=2&&mcqPct>=75,result.mcqCorrect+"/28 MCQ; "+stimMiss+" source-based misses and "+directMiss+" content misses.","Before choices, mark the title/date/speaker/labels and predict the answer in your own words.",stimMiss>=Math.max(3,directMiss)),skillRow("Context and relationships",contextMiss+relationMiss===0,(contextMiss+relationMiss)+" context or relationship rubric targets still open.","Start each response with the setting, then name the relationship: cause/effect, similarity/difference, or turning point.",contextMiss+relationMiss>=2),skillRow("Document evidence",docMiss===0&&result.essayScore.docHits>=minDocs,result.essayScore.docHits+" essay documents detected; "+docMiss+" evidence targets still open.","Quote or paraphrase precise evidence from at least "+docNeed+" essay documents and from both short-answer documents.",docMiss>=2||result.essayScore.docHits<minDocs),skillRow("Outside information",outsideMiss===0,outsideMiss+" outside-information targets still open.","Add one accurate course fact beyond the documents to each short essay and at least one to the long essay.",outsideMiss>=2),skillRow("Argument and organization",argumentMiss===0,argumentMiss+" analysis or organization targets still open.","Use claim, evidence, explanation paragraphs. Every document detail should be followed by why it matters.",argumentMiss>=2),skillRow("Pacing",!slow.length,slow.length?slow.join(", ")+" ran well past the target pace.":"No section was far past its target pace.","Move on from stuck MCQs after about two minutes and bank time for writing.",!!slow.length)];if(scaffoldRow)rows.splice(3,0,scaffoldRow);return rows}
function weakTopicLabels(result,skills){return uniq([...topMissedSets(result.missed).map(t=>t[0]),...skills.filter(row=>row.weak).map(row=>row.label)]).slice(0,8)}
function nextPracticePlan(result,skills,targets){const weak=skills.filter(row=>row.weak).map(row=>row.label).join(" ");const actions=[];if(/MCQ source reading/i.test(weak))actions.push({title:"10-minute Source Sprint",body:"Build the stimulus habit before another full exam.",href:"../source-sprint/"});if(/Document evidence|Context|Outside information|Argument|Civic SAQ/i.test(weak))actions.push({title:"Rewrite The Lowest Writing Part",body:"Use Review Writing below, then resubmit after adding the missing rubric moves."});if(targets.length)actions.push({title:"Targeted Topic Board",body:"Use Jeopardy or Gauntlet for "+targets[0][0]+" while the miss is fresh.",href:"../../index.html#jeopardy"});if((result.conversion.scale||0)>=85)actions.push({title:"Fresh Full Exam",body:"You are in scoring range. Take a new timed build and protect the writing score.",href:"./"});if(!actions.length)actions.push({title:"Mixed Regents Gauntlet",body:"Keep reps varied: source MCQs, explanations, then a fresh practice exam.",href:"../regents-gauntlet/"});return actions.slice(0,4)}
function coachComments(result){const comments=[];const mcqPct=Math.round(result.mcqCorrect/28*100);comments.push(["MCQ accuracy",mcqPct+"% on the 28-question section. "+(mcqPct>=80?"Keep doing mixed timed sets so source reading stays sharp.":mcqPct>=65?"You are close; the fastest gain is reviewing missed source questions by topic.":"This needs daily mixed MCQ practice with stimulus annotation before answer choice elimination.")]);const stimMiss=result.missed.filter(sourceBased).length;const directMiss=result.missed.length-stimMiss;if(stimMiss>=directMiss&&stimMiss>0)comments.push(["Stimulus reading","Most missed MCQs were source-based. Read the title, date, speaker, and visual labels before looking at the choices."]);else if(directMiss>0)comments.push(["Content recall","Several misses were direct content questions. Build a one-page hit list of the names, laws, events, and concepts that appear in the missed set."]);result.shortScores.forEach((s,i)=>comments.push([state.exam.shortTasks[i].title,s.score+"/"+s.max+" approx. "+s.comments[0]]));(result.scaffoldScores||[]).forEach((s,i)=>comments.push([state.exam.scaffoldTasks[i].title,s.score+"/"+s.max+" approx. "+s.comments[0]]));comments.push([state.profile.essayTitle,result.essayScore.score+"/"+result.essayScore.max+" approx. "+result.essayScore.comments[0]]);return comments}
function renderScale(score,max){const steps=Array.from({length:max*2+1},(_,i)=>i/2);return '<div class="guide-scale half">'+steps.map(v=>'<div class="guide-step '+(v<=score?'hit ':'')+(v===score?'current':'')+'">'+(Number.isInteger(v)?v:v.toFixed(1))+'</div>').join("")+'</div>'}
function renderChecks(checks){return '<div class="guide-checks">'+checks.map(c=>'<div class="check '+(c.pass?'pass':'miss')+'">'+(c.pass?'Met: ':'Next: ')+esc(c.pass?c.label:c.next)+'</div>').join("")+'</div>'}
function modelBlock(model,answerKey){const key=Array.isArray(answerKey)?'<ul>'+answerKey.map(item=>'<li>'+esc(item)+'</li>').join("")+'</ul>':answerKey?'<p>'+esc(answerKey)+'</p>':"";if(!model&&!key)return "";return '<details class="model-answer"><summary>Answer key and model response</summary>'+key+(model?'<p>'+esc(model)+'</p>':"")+'</details>'}
function guideCard(title,score,max,position,checks,note,sourceNote){const guideNote=checks&&checks.length?guidePositionNote(Number(score)||0,Number(max)||0,checks,note):note;return '<article class="guide-card"><div class="guide-head"><strong>'+esc(title)+'</strong><span class="score-badge">'+esc(score+'/'+max)+'</span></div>'+renderScale(score,max)+'<p class="guide-note"><strong>'+esc(position)+'.</strong> '+esc(guideNote||"")+'</p>'+renderChecks(checks||[])+'<p class="guide-note">'+esc(sourceNote||"")+'</p></article>'}
function renderRubricGuide(r){const conversion=r.conversion||{};const convTitle="Official "+esc(state.exam.administration)+" Conversion Chart Estimate";const convScore=conversion.scale==null?"n/a":String(conversion.scale);let html='<article class="guide-card"><div class="guide-head"><strong>'+convTitle+'</strong><span class="score-badge">'+esc(convScore+(conversion.level?' · '+conversion.level:""))+'</span></div><p class="guide-note">'+esc(conversion.note||"Conversion chart unavailable.")+'</p><p class="guide-note">'+esc(state.profile.guideSource.replace("January 2026",state.exam.administration))+'</p></article>';r.shortScores.forEach((s,i)=>{const task=state.exam.shortTasks[i];html+=guideCard(task.title,s.score,s.max,s.position,s.checks,s.comments[0],s.sourceNote)+modelBlock(task.modelAnswer,task.answerKey)});(r.scaffoldScores||[]).forEach((s,i)=>{const task=state.exam.scaffoldTasks[i];html+=guideCard(task.title,s.score,s.max,s.position,s.checks,s.comments[0],s.sourceNote)+modelBlock(task.modelAnswer,task.answerKey)});html+=guideCard(state.profile.essayTitle,r.essayScore.score,r.essayScore.max,r.essayScore.position,r.essayScore.checks,r.essayScore.comments[0],r.essayScore.sourceNote)+modelBlock(state.exam.essay.modelEssay,state.exam.essay.answerKey);$("#rubricGuide").innerHTML=html}
function submitExam(expired){if(state.submitted)return;if(!expired){const unanswered=state.exam.mcq.filter(q=>!state.answers[q.id]).length;if(unanswered&&!confirm("You still have "+unanswered+" unanswered multiple-choice questions. Submit anyway?"))return}state.sectionMs=currentSectionMs();state.submitted=true;if(state.timer)clearInterval(state.timer);const result=gradeExam();state.result=result;clearSaved();const skills=skillReport(result);const targets=weakTopicLabels(result,skills);window.MrMacsAnalytics?.track("game_complete",{gameId:"regents-practice-exam",title:state.profile.title,course:state.exam.course,gameType:"Full Practice Exam",score:result.percent,accuracy:Math.round(result.mcqCorrect/28*100),questions:28,weakTopics:targets},{counter:"game-completions"});renderResults(expired)}
function renderResults(expired){const r=state.result;show("resultsScreen");$("#timerStrip").innerHTML='<span class="pill">Practice complete</span><span class="pill">Practice estimate, not official scoring</span>';$("#resultTitle").textContent=state.profile.label+" Score Report";$("#resultMetrics").innerHTML=[[(r.conversion.scale??r.percent)+"","Regents scale estimate"],[r.conversion.level||"Level n/a","performance level"],[r.raw+"/"+r.rawMax,"raw practice points"],[r.mcqCorrect+"/28","MCQ"],[(r.shortTotal+r.scaffoldTotal+r.essayScore.score)+"/"+(state.profile.shortMax+(state.profile.scaffoldMax||0)+state.profile.essayMax),"writing"]].map(m=>'<div class="metric"><strong>'+esc(m[0])+'</strong><span>'+esc(m[1])+'</span></div>').join("");const comments=coachComments(r);if(expired)comments.unshift(["Timer","The exam submitted when time expired. Practice pacing by moving on from stuck MCQs after about two minutes."]);comments.unshift(["Practice estimate","Practice estimate, not official scoring. This uses the selected exam's official MCQ key, rubric signals, and conversion chart when available; it is not an official NYSED score."]);$("#coachComments").innerHTML=comments.map(c=>'<div class="feedback-card"><strong>'+esc(c[0])+'</strong>'+esc(c[1])+'</div>').join("");const targets=topMissedSets(r.missed);const skills=skillReport(r);const actions=nextPracticePlan(r,skills,targets);const actionHtml=actions.map(a=>'<div class="feedback-card action-card"><strong>'+esc(a.title)+'</strong>'+esc(a.body)+(a.href?' <a class="mini-link" href="'+esc(a.href)+'">Open</a>':"")+'</div>').join("");const skillHtml=skills.map(row=>'<div class="feedback-card skill-card '+esc(row.status.toLowerCase())+'"><strong>'+esc(row.label)+' · '+esc(row.status)+'</strong>'+esc(row.detail)+'<br><span>'+esc(row.next)+'</span></div>').join("");const targetHtml=(targets.length?targets.map(t=>'<div class="feedback-card"><strong>'+esc(t[0])+'</strong>'+esc(t[1])+' missed or weak signal</div>'):[["No major MCQ target","Use a harder mixed bank next."]].map(t=>'<div class="feedback-card"><strong>'+esc(t[0])+'</strong>'+esc(t[1])+'</div>')).join("");$("#studyTargets").innerHTML=actionHtml+skillHtml+targetHtml;renderRubricGuide(r);$("#reviewList").innerHTML=state.exam.mcq.map((q,i)=>{const chosen=state.answers[q.id];const ok=chosen===q.correct;const right=q.displayedChoices.find(c=>c.label===q.correct);const picked=q.displayedChoices.find(c=>c.label===chosen);return '<div class="review-item '+(ok?'correct':'missed')+'"><strong>Question '+(i+1)+' · '+(ok?'Correct':'Missed')+'</strong><br>'+esc(q.stem)+'<br><span class="source-line">'+esc(q.source+" · "+q.set)+'</span><br>Your answer: '+esc(chosen?(chosen+". "+(picked?.text||"")):"blank")+'<br>Correct: '+esc(q.correct+". "+(right?.text||""))+'<br>'+esc(q.explanation||"Review this source and topic.")+'</div>'}).join("")}
function reviewWriting(){show("examScreen");state.submitted=false;switchSection("short");state.submitted=true}
function publishDebug(){if(new URLSearchParams(location.search).has("debug"))window.__RegentsPracticeDebug={state,assembleExam,docGroupKey,docAssetKeys,writingDocAudit}}

