document.addEventListener("click",event=>{const target=event.target instanceof Element?event.target:null;const btn=target?.closest("[data-inspect-src]");if(btn){openStimulusViewer(btn.dataset.inspectSrc,btn.dataset.inspectLabel,btn.dataset.inspectSource)}});
document.addEventListener("error",event=>{const img=event.target instanceof HTMLImageElement?event.target:null;if(!img||!img.dataset.sourceImg||img.dataset.sourceMissing)return;img.dataset.sourceMissing="1";const figure=img.closest(".stimulus-figure");if(figure){figure.classList.add("stimulus-missing");const note=document.createElement("p");note.className="source-line";note.textContent="Source image did not load. This item has been flagged for repair.";figure.append(note)}},true);
