document.addEventListener("keydown",event=>{if($("#stimulusViewer").classList.contains("hidden"))return;if(event.key==="Escape")closeStimulusViewer();if(event.key==="ArrowLeft")stepStimulusViewer(-1);if(event.key==="ArrowRight")stepStimulusViewer(1);if(event.key==="+"||event.key==="=")setStimulusZoom(viewer.zoom+.1);if(event.key==="-"||event.key==="_")setStimulusZoom(viewer.zoom-.1)});
